#include<bits/stdc++.h>
using namespace std;

const int N = 5e5 + 5;

vector<int> e[N];

vector<int> bcc[N];

int s[N], low[N], dfn[N];
int dfncnt, tp, bcc_cnt;

void tarjan(int u, int fa)
{
    s[++tp] = u, low[u] = dfn[u] = ++dfncnt;
    int t = 0;
    for(int v : e[u])
    {
        if(!dfn[v])
            tarjan(v, u), low[u] = min(low[v], low[u]);
        else
        {
            if(v == fa) ++t;
            if(v != fa || t >= 2) low[u] = min(low[u], dfn[v]);
        }
    }
    if(low[u] == dfn[u])
    {
        int id = ++bcc_cnt;
        do
        {
            bcc[id].push_back(s[tp]);
        }while(s[tp--] != u);
    }
}

int main()
{
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= m; i++)
    {
        int x, y;
        cin >> x >> y;
        e[x].push_back(y);
        e[y].push_back(x);
    }
    for(int i = 1; i <= n; i++)
        if(!dfn[i]) tarjan(i, i);
    cout << bcc_cnt << '\n';
    for(int i = 1; i <= bcc_cnt; i++)
    {
        cout << bcc[i].size() << ' ';
        for(int x : bcc[i])
            cout << x << ' ';
        cout << '\n';
    }
    return 0;
}
